#include<bits/stdc++.h>
using namespace std;
char s[10000001];
int b[27];
int a,j;
int z(int &f){
	if(f==0||f==1){
		return 0;
	}
	for(int i=2;i<=sqrt(f);i++){
		if(f%i==0)
		{
			return 0;
		}
	}
	return 1;
}
int main()
{

	cin>>s;
	int len=strlen(s);
	for(int i=0;i<len;i++){
		b[s[i]-'a']++;
	}
	sort(b,b+26);
	for(int i=0;i<26;i++){
		if(b[i]==0){
			j++;
		}
	}
	int f=b[25]-b[j];
	if(z(f)==1){
		cout<<"Lucky Word"<<"\n"<<f;
	}else{
		cout<<"No Answer"<<"\n"<<0;
	}
	return 0;
}
